/**
 * Draws a 'dot' on the given canvas.
 *
 * @param ctx
 * @param p
 */
function drawCircle(ctx, radius, strokeStyle, fillStyle) {
    return (p) => {
        if (strokeStyle) {
            ctx.strokeStyle = strokeStyle;
        }
        if (fillStyle) {
            ctx.fillStyle = fillStyle;
        }
        ctx.beginPath();
        ctx.arc(p[0], p[1], radius, 0, 2 * Math.PI);
        if (strokeStyle) {
            ctx.stroke();
        }
        if (fillStyle) {
            ctx.fill();
        }
    };
}


